__kernel void compute_distances(
    __global const char* sandbox,
    const int rec_length,
    const int latitude_pos,
    const float target_lat,
    const float target_long,
    const int rec_count,
    __global float* z)
{
    int i = get_global_id(0);
    if (i < rec_count) {
        int base_idx = i * rec_length + latitude_pos - 1;

        // Extract latitude string (up to 10 chars, null-terminated)
        char lat_str[11];
        for (int c = 0; c < 10; c++) {
            lat_str[c] = sandbox[base_idx + c];
        }
        lat_str[10] = '\0';

        // Extract longitude string (up to 10 chars, null-terminated)
        char long_str[11];
        for (int c = 0; c < 10; c++) {
            long_str[c] = sandbox[base_idx + 10 + c];
        }
        long_str[10] = '\0';

        // Convert strings to float using strtof
        float tmp_lat = strtof(lat_str, NULL);
        float tmp_long = strtof(long_str, NULL);

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;
        z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
    }
}
